1	export interface Item {
2	  type: string;
3	}
4	
5	export interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	export interface Scenario {
11	  customer: { yearsWithMHPCO: number };
12	  steps: QuoteStep[];
13	}
14	
15	export interface ScenarioResult {
16	  results: { premium: number }[];
17	}
18	
19	const PROCESSING_FEE = 5;
20	
21	const BASE_PRICE_BY_TYPE: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	};
27	
28	const basePriceFor = (item: Item): number => BASE_PRICE_BY_TYPE[item.type];
29	
30	const quotePremium = (step: QuoteStep): number =>
31	  step.items.reduce((sum, item) => sum + basePriceFor(item), 0) + PROCESSING_FEE;
32	
33	export const runScenario = (scenario: Scenario): ScenarioResult => ({
34	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
35	});
36

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item type ---
15	  it("single sword → premium 105 G (100 base + 5 fee)", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 105 }] });
21	  });
22	  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 65 }] });
28	  });
29	  it("single staff → premium 85 G (80 base + 5 fee)", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 85 }] });
35	  });
36	  it("single potion → premium 45 G (40 base + 5 fee)", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 45 }] });
42	  });
43	
44	  // --- Components and building blocks ---
45	  it.todo("2 runes → 50 G base premium (+5 fee = 55 G)");
46	  it.todo("3 runes → 60 G base premium (block applies, +5 fee = 65 G)");
47	  it.todo("4 runes → 100 G base premium (no block, +5 fee = 105 G)");
48	  it.todo("7 runes → 175 G base premium (one block + 4 singles, +5 fee = 180 G)");
49	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types, +5 fee = 80 G)");
50	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks, +5 fee = 125 G)");
51	
52	  // --- Modifiers ---
53	  it.todo("cursed sword adds 50% risk surcharge (100 + 50 + 5 = 155 G)");
54	  it.todo("high-enchantment (≥5) sword adds 30% surcharge (100 + 30 + 5 = 135 G)");
55	  it.todo("sword with exactly enchantment 5 → high-enchantment applies (135 G)");
56	  it.todo("sword with enchantment 4 → no high-enchantment surcharge (105 G)");
57	  it.todo("cursed sword with enchantment 5 → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");
58	  it.todo("long-standing customer (≥2 years) gets 20% loyalty discount");
59	  it.todo("customer with exactly 2 years → loyalty discount applies");
60	  it.todo("first insurance carries 10% surcharge on policy base");
61	  it.todo("follow-up contract (after first) gets 15% discount");
62	  it.todo("processing fee of 5 G is added to every premium");
63	
64	  // --- Rounding ---
65	  it.todo("premium rounded up in MHPCO favor (197.5 → 198 G)");
66	  it.todo("payout rounded down in MHPCO favor (350.5 → 350 G)");
67	
68	  // --- Multi-item policies and modifier scope ---
69	  it.todo("policy with cursed sword + plain amulet → 210 G (cursed applies to sword's base only)");
70	
71	  // --- Integration examples ---
72	  it.todo("newcomer with cursed sword (steel, ench 3): 0 years, no prior → 165 G");
73	  it.todo("long-standing customer's second contract (cursed sword, ench 7, 3 years) → 160 G");
74	
75	  // --- Claim processing: standard reimbursement ---
76	  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 deductible)");
