78	
79	  // --- Claim: high enchantment clause ---
80	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% then deductible)");
81	
82	  // --- Claim: dragon material ---
83	  it.todo("dragon-material sword, ench 5, damage 800 G → payout 700 G (full, then deductible)");
84	
85	  // --- Claim: enchantment + dragon combined ---
86	  it.todo("dragon-material sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
