98	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
99	  it.todo("cursed sword policy → cap 2000 G (based on unmodified insurance value)");
100	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
101	  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 (cap 600), second payout 600 (cap 0)");
102	
