104	  it.todo("quote with unknown item type → CLI exits non-zero, stderr error, no results");
105	  it.todo("claim references item not in policy → CLI exits non-zero with stderr");
106	  it.todo("claim with negative damage amount → CLI exits non-zero with stderr");
107	});
